import { Request, Response, NextFunction } from "express";

interface AppError extends Error {
  statusCode: number;
}

function errorHandler(
  err: AppError,
  req: Request,
  res: Response,
  next: NextFunction
): void {
  const status = err.statusCode || 500;
  res.status(status).json({
    error: err.message,
    path: req.originalUrl,
  });
}
